sys_script_include.script:
var PatientUtils = Class.create();
PatientUtils.prototype = {
    initialize: function() {
    },
	getPatientDetailsById : function(patientId){
		var res = {};
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			res.sys_id = gr.getUniqueValue();
			res.name = gr.getValue('u_first_name');
			res.DOB = gr.getValue('u_date_of_birth');
			res.gender = gr.getValue('u_gender');
		}
		return res;
	},

	checkVip : function(patientId){
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			return gr.getValue('u_vip')==true || gr.getValue('u_vip')=='true';
		}
		return false;
	},

	getAge : function(patientId){
		var gr = new GlideRecord('u_patient_record');
		if(gr.get('u_number',patientId)){
			var dobstr = gr.getValue('u_date_of_birth');
			var dob = new GlideDate();
			dob.setValue(dobstr);
			var now = new GlideDate();

			var dobinmills = dob.getNumericValue();
			var nowinmills = now.getNumericValue();

			var diffinmills = Math.abs(dobinmills-nowinmills);
			var ageinyrs = Math.floor(diffinmills/(1000*60*60*24*365.25));

			return ageinyrs;
		}
	},

    type: 'PatientUtils'
};
